import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import * as api from '../../utils/api';

const GraphViz = ({ highlightPath = [] }) => {
  const svgRef = useRef();
  const [edges, setEdges] = useState([]);
  const [hospitals, setHospitals] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [tooltip, setTooltip] = useState(null);

  useEffect(() => {
    Promise.all([api.getGraphEdges(), api.getHospitals()])
      .then(([edgesRes, hospitalsRes]) => {
        setEdges(edgesRes.data.data || []);
        setHospitals(hospitalsRes.data.data || []);
      })
      .catch((err) => setError(err.message))
      .finally(() => setLoading(false));
  }, []);

  useEffect(() => {
    if (loading) return;
    if (hospitals.length === 0) return;
    drawGraph();
  }, [edges, hospitals, highlightPath, loading]);

  const drawGraph = () => {
    const container = svgRef.current?.parentElement;
    if (!container) return;
    const W = container.clientWidth || 800;
    const H = 520;

    d3.select(svgRef.current).selectAll('*').remove();

    const svg = d3.select(svgRef.current)
      .attr('width', W)
      .attr('height', H);

    // Glow filter
    const defs = svg.append('defs');
    const glow = defs.append('filter').attr('id', 'glow');
    glow.append('feGaussianBlur').attr('stdDeviation', '3').attr('result', 'coloredBlur');
    const feMerge = glow.append('feMerge');
    feMerge.append('feMergeNode').attr('in', 'coloredBlur');
    feMerge.append('feMergeNode').attr('in', 'SourceGraphic');

    svg.append('rect').attr('width', W).attr('height', H).attr('fill', '#0a1628');

    // Build nodeId → hospital map
    const nodeMap = new Map(hospitals.map((h) => [h.nodeId, h]));

    // If no edges, just show hospitals as standalone nodes
    let nodes, links;

    if (edges.length === 0) {
      nodes = hospitals
        .filter(h => h.nodeId)
        .map(h => ({ id: h.nodeId, ...h }));
      links = [];
    } else {
      // Collect all nodeIds that appear in edges AND exist in hospitals
      const validNodeIds = new Set(
        edges.flatMap(e => [e.fromNodeId, e.toNodeId])
             .filter(id => nodeMap.has(id))
      );

      // Also add hospitals that have a nodeId but no edges yet
      hospitals.forEach(h => { if (h.nodeId) validNodeIds.add(h.nodeId); });

      nodes = Array.from(validNodeIds).map(id => ({
        id,
        ...(nodeMap.get(id) || { name: id, beds: {}, fees: {} }),
      }));

      // Only keep edges where BOTH endpoints are valid nodes
      const nodeIdSet = new Set(nodes.map(n => n.id));
      const seen = new Set();
      links = edges
        .filter(e => nodeIdSet.has(e.fromNodeId) && nodeIdSet.has(e.toNodeId))
        .filter(e => {
          const key = [e.fromNodeId, e.toNodeId].sort().join('|');
          if (seen.has(key)) return false;
          seen.add(key);
          return true;
        })
        .map(e => ({
          source: e.fromNodeId,
          target: e.toNodeId,
          distance: e.distanceKm,
          time: e.travelTimeMinutes,
        }));
    }

    if (nodes.length === 0) {
      svg.append('text')
        .attr('x', W / 2).attr('y', H / 2)
        .attr('text-anchor', 'middle')
        .attr('fill', '#94a3b8').attr('font-size', 14)
        .text('No hospitals in the network yet');
      return;
    }

    const highlightSet = new Set();
    for (let i = 0; i < highlightPath.length - 1; i++) {
      highlightSet.add([highlightPath[i], highlightPath[i + 1]].sort().join('|'));
    }

    // Deep-copy nodes so D3 can mutate x/y freely
    const simNodes = nodes.map(n => ({ ...n }));
    const nodeById = new Map(simNodes.map(n => [n.id, n]));

    // Map links to use actual node objects
    const simLinks = links.map(l => ({
      ...l,
      source: nodeById.get(l.source) || l.source,
      target: nodeById.get(l.target) || l.target,
    }));

    const simulation = d3.forceSimulation(simNodes)
      .force('link', d3.forceLink(simLinks)
        .id(d => d.id)
        .distance(d => Math.min((d.distance || 10) * 8, 200))
      )
      .force('charge', d3.forceManyBody().strength(-450))
      .force('center', d3.forceCenter(W / 2, H / 2))
      .force('collision', d3.forceCollide(60));

    // Draw links
    const link = svg.append('g').selectAll('line').data(simLinks).join('line')
      .attr('stroke', d => {
        const src = d.source?.id || d.source;
        const tgt = d.target?.id || d.target;
        const key = [src, tgt].sort().join('|');
        return highlightSet.has(key) ? '#f59e0b' : 'rgba(0,196,180,0.25)';
      })
      .attr('stroke-width', d => {
        const src = d.source?.id || d.source;
        const tgt = d.target?.id || d.target;
        return highlightSet.has([src, tgt].sort().join('|')) ? 3 : 1.5;
      });

    // Draw link distance labels
    const linkLabel = svg.append('g').selectAll('text').data(simLinks).join('text')
      .attr('fill', 'rgba(148,163,184,0.7)')
      .attr('font-size', 10)
      .attr('text-anchor', 'middle')
      .text(d => d.distance ? `${d.distance}km` : '');

    // Draw node groups
    const node = svg.append('g').selectAll('g').data(simNodes).join('g')
      .call(d3.drag()
        .on('start', (e, d) => { if (!e.active) simulation.alphaTarget(0.3).restart(); d.fx = d.x; d.fy = d.y; })
        .on('drag', (e, d) => { d.fx = e.x; d.fy = e.y; })
        .on('end', (e, d) => { if (!e.active) simulation.alphaTarget(0); d.fx = null; d.fy = null; })
      )
      .on('mouseenter', (e, d) => setTooltip({ hospital: d, x: e.clientX, y: e.clientY }))
      .on('mouseleave', () => setTooltip(null));

    node.append('circle')
      .attr('r', d => highlightPath.includes(d.id) ? 24 : 20)
      .attr('fill', d => {
        if (highlightPath.includes(d.id)) return '#f59e0b';
        const avail = d.beds?.available ?? 0;
        if (avail > 50) return 'rgba(16,185,129,0.85)';
        if (avail > 10) return 'rgba(0,196,180,0.85)';
        if (avail > 0) return 'rgba(245,158,11,0.85)';
        return 'rgba(239,68,68,0.75)';
      })
      .attr('stroke', d => highlightPath.includes(d.id) ? '#fff' : 'rgba(255,255,255,0.2)')
      .attr('stroke-width', 2)
      .attr('filter', d => highlightPath.includes(d.id) ? 'url(#glow)' : '');

    // Beds count inside circle
    node.append('text')
      .attr('dy', 4).attr('text-anchor', 'middle')
      .attr('fill', 'white').attr('font-size', 10).attr('font-weight', 700)
      .attr('pointer-events', 'none')
      .text(d => d.beds?.available ?? '?');

    // Hospital name below circle
    node.append('text')
      .attr('dy', 36).attr('text-anchor', 'middle')
      .attr('fill', '#f8fafc').attr('font-size', 11).attr('font-weight', 500)
      .attr('pointer-events', 'none')
      .text(d => d.name ? d.name.split(' ').slice(0, 2).join(' ') : d.id);

    simulation.on('tick', () => {
      link
        .attr('x1', d => d.source.x).attr('y1', d => d.source.y)
        .attr('x2', d => d.target.x).attr('y2', d => d.target.y);
      linkLabel
        .attr('x', d => (d.source.x + d.target.x) / 2)
        .attr('y', d => (d.source.y + d.target.y) / 2 - 5);
      node.attr('transform', d => `translate(${d.x},${d.y})`);
    });
  };

  if (loading) return <div className="loading-center"><div className="spinner" /></div>;

  if (error) return (
    <div style={{ padding: 24, color: 'var(--red)', background: 'rgba(239,68,68,0.08)', borderRadius: 12, textAlign: 'center' }}>
      ⚠ Failed to load graph: {error}
    </div>
  );

  return (
    <div style={{ position: 'relative' }}>
      <div style={{ display: 'flex', gap: 20, marginBottom: 12, flexWrap: 'wrap' }}>
        {[
          { color: '#10b981', label: 'High availability (>50 beds)' },
          { color: '#00c4b4', label: 'Medium (10–50 beds)' },
          { color: '#f59e0b', label: 'Low (1–10 beds)' },
          { color: '#ef4444', label: 'No beds available' },
          { color: '#f59e0b', label: 'Shortest path highlighted', border: true },
        ].map(({ color, label, border }) => (
          <div key={label} style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
            <div style={{ width: 10, height: 10, borderRadius: '50%', background: color, border: border ? '2px solid white' : 'none' }} />
            <span style={{ fontSize: 12, color: 'var(--slate)' }}>{label}</span>
          </div>
        ))}
        <span style={{ fontSize: 12, color: 'var(--slate)' }}>• Drag nodes to rearrange</span>
      </div>

      <svg ref={svgRef} style={{ borderRadius: 12, border: '1px solid var(--border)', display: 'block', width: '100%' }} />

      {tooltip && (
        <div style={{
          position: 'fixed', left: tooltip.x + 14, top: tooltip.y - 70,
          background: 'var(--navy-light)', border: '1px solid var(--border)',
          borderRadius: 10, padding: '12px 16px', pointerEvents: 'none',
          zIndex: 999, boxShadow: 'var(--shadow)', minWidth: 210,
        }}>
          <div style={{ fontWeight: 600, marginBottom: 3 }}>{tooltip.hospital.name || tooltip.hospital.id}</div>
          <div style={{ fontSize: 12, color: 'var(--slate)', marginBottom: 6 }}>{tooltip.hospital.location?.city}</div>
          <div style={{ fontSize: 12 }}>
            <span style={{ color: 'var(--green)' }}>Available: {tooltip.hospital.beds?.available ?? '?'}</span>
            {' / '}
            <span style={{ color: 'var(--slate)' }}>Total: {tooltip.hospital.beds?.total ?? '?'}</span>
          </div>
          {tooltip.hospital.fees?.opd > 0 && (
            <div style={{ fontSize: 12, color: 'var(--teal)', marginTop: 3 }}>
              OPD: ₹{tooltip.hospital.fees.opd} · ICU: ₹{tooltip.hospital.fees.icu}/day
            </div>
          )}
          <div style={{ fontSize: 11, color: 'var(--slate)', marginTop: 4, fontFamily: 'monospace' }}>
            Node: {tooltip.hospital.id}
          </div>
        </div>
      )}
    </div>
  );
};

export default GraphViz;
